<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);require_once__DIR__.'/calendar_config.php';require_once__DIR__.'/config.php';/AddthisforAPI_BASE_URLclassScheduleManager{private$pdo;publicfunction__construct(){try{$this->pdo=newPDO("mysql:host=".DB_HOST.";dbname=".DB_NAME,DB_USER,DB_PASS);$this->pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);}catch(PDOException$e){die("Databaseconnectionfailed:".$e->getMessage());}}publicfunctioncreateSchedule($data){try{$stmt=$this->pdo->prepare("INSERTINTOschedules(personil_id,personil_name,bagian,shift_type,shift_date,start_time,end_time,location,description,google_event_id)VALUES(?,?,?,?,?,?,?,?,?,?)");$stmt->execute([$data['personil_id'],$data['personil_name'],$data['bagian'],$data['shift_type'],$data['shift_date'],$data['start_time'],$data['end_time'],$data['location']??'',$data['description']??'',$data['google_event_id']??null]);return['success'=>true,'schedule_id'=>$this->pdo->lastInsertId()];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctionupdateSchedule($scheduleId,$data){try{$fields=[];$values=[];forforeach(['personil_id','personil_name','bagian','shift_type','shift_date','start_time','end_time','location','description','google_event_id','status']as$field){if(isset($data[$field])){$fields[]="$field=?";$values[]=$data[$field];}}if(empty($fields)){return['success'=>false,'error'=>'Nofieldstoupdate'];}$values[]=$scheduleId;$stmt=$this->pdo->prepare("UPDATEschedulesSET".implode(',',$fields).",updated_at=CURRENT_TIMESTAMPWHEREid=?");$stmt->execute($values);return['success'=>true];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctiondeleteSchedule($scheduleId){try{/GetGoogleeventIDfirst$stmt=$this->pdo->prepare("SELECTgoogle_event_idFROMschedulesWHEREid=?");$stmt->execute([$scheduleId]);$schedule=$stmt->fetch(PDO::FETCH_ASSOC);/Deletefromdatabase$stmt=$this->pdo->prepare("DELETEFROMschedulesWHEREid=?");$stmt->execute([$scheduleId]);return['success'=>true,'google_event_id'=>$schedule['google_event_id']??null];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctiongetSchedules($filters=[]){try{$sql="SELECT*FROMschedulesWHERE1=1";$params=[];if(!empty($filters['personil_id'])){$sql.="ANDpersonil_id=?";$params[]=$filters['personil_id'];}if(!empty($filters['bagian'])){$sql.="ANDbagian=?";$params[]=$filters['bagian'];}if(!empty($filters['shift_type'])){$sql.="ANDshift_type=?";$params[]=$filters['shift_type'];}if(!empty($filters['date_from'])){$sql.="ANDshift_date>=?";$params[]=$filters['date_from'];}if(!empty($filters['date_to'])){$sql.="ANDshift_date<=?";$params[]=$filters['date_to'];}$sql.="ORDERBYshift_date,start_time";$stmt=$this->pdo->prepare($sql);$stmt->execute($params);$schedules=$stmt->fetchAll(PDO::FETCH_ASSOC);return['success'=>true,'schedules'=>$schedules];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctioncreateOperation($data){try{$stmt=$this->pdo->prepare("INSERTINTOoperations(operation_name,operation_date,start_time,end_time,location,description,required_personnel,google_event_id)VALUES(?,?,?,?,?,?,?,?)");$stmt->execute([$data['operation_name'],$data['operation_date'],$data['start_time'],$data['end_time'],$data['location'],$data['description']??'',$data['required_personnel']??0,$data['google_event_id']??null]);return['success'=>true,'operation_id'=>$this->pdo->lastInsertId()];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctionassignPersonnelToOperation($operationId,$assignments){try{$stmt=$this->pdo->prepare("INSERTINTOassignments(operation_id,personil_id,personil_name,role)VALUES(?,?,?,?)");forforeach($assignmentsas$assignment){$stmt->execute([$operationId,$assignment['personil_id'],$assignment['personil_name'],$assignment['role']??'']);}return['success'=>true];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctiongetOperations($filters=[]){try{$sql="SELECTo.*,COUNT(a.id)asassigned_countFROMoperationsoLEFTJOINassignmentsaONo.id=a.operation_idWHERE1=1";$params=[];if(!empty($filters['date_from'])){$sql.="ANDo.operation_date>=?";$params[]=$filters['date_from'];}if(!empty($filters['date_to'])){$sql.="ANDo.operation_date<=?";$params[]=$filters['date_to'];}if(!empty($filters['status'])){$sql.="ANDo.status=?";$params[]=$filters['status'];}$sql.="GROUPBYo.idORDERBYo.operation_date,o.start_time";$stmt=$this->pdo->prepare($sql);$stmt->execute($params);$operations=$stmt->fetchAll(PDO::FETCH_ASSOC);/Getassignmentsforeachoperationforforeach($operationsas&$operation){$stmt=$this->pdo->prepare("SELECT*FROMassignmentsWHEREoperation_id=?");$stmt->execute([$operation['id']]);$operation['assignments']=$stmt->fetchAll(PDO::FETCH_ASSOC);}return['success'=>true,'operations'=>$operations];}catch(PDOException$e){return['success'=>false,'error'=>$e->getMessage()];}}publicfunctiongetPersonilFromAPI(){try{/UseAPItogetALLpersonildatafromdatabase$api_url=API_BASE_URL.'/personil_simple.php?limit=1000';$ch=curl_init();curl_setopt($ch,CURLOPT_URL,$api_url);curl_setopt($ch,CURLOPT_RETURNTRANSFER,true);curl_setopt($ch,CURLOPT_TIMEOUT,30);curl_setopt($ch,CURLOPT_SSL_VERIFYPEER,false);$response=curl_exec($ch);$http_code=curl_getinfo($ch,CURLINFO_HTTP_CODE);curl_close($ch);if($http_code!==200){thrownewException("APIrequestfailedwithHTTPcode:$http_code");}$data=json_decode($response,true);if(!$data||!$data['success']){thrownewException("APIrequestfailed:".($data['error']['message']??'Unknownerror'));}$personilList=[];$personilData=$data['data']['personil'];/Processpersonildataforforeach($personilDataas$personil){$personilList[]=['id'=>$personil['nrp'],'name'=>$personil['nama'],'pangkat'=>$personil['pangkat_singkatan']??$personil['nama_pangkat'],'jabatan'=>$personil['nama_jabatan'],'bagian'=>$personil['nama_bagian']??'TANPABAGIAN','status'=>$personil['status_ket']??'aktif','status_kepegawaian'=>$personil['status_kepegawaian']];}return['success'=>true,'personil'=>$personilList,'total'=>count($personilList),'statistics'=>$data['data']['statistics']];}catch(Exception$e){/FallbacktodatabaseifAPIfailstry{$pdo=newPDO("mysql:host=".DB_HOST.";dbname=".DB_NAME.";unix_socket=".DB_SOCKET,DB_USER,DB_PASS);$pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$stmt=$pdo->query("SELECTp.id,p.nama,p.nrp,b.nama_bagian,pg.nama_pangkatFROMpersonilpLEFTJOINbagianbONp.bagian_id=b.idLEFTJOINpangkatpgONp.pangkat_id=pg.idWHEREp.is_deleted=0ANDp.is_active=1ORDERBYb.nama_bagian,p.nama");$personilList=$stmt->fetchAll(PDO::FETCH_ASSOC);return['success'=>true,'personil'=>$personilList,'total'=>count($personilList)];}catch(Exception$dbEx){return['success'=>false,'error'=>'Failedtoloadpersonildata:'.$e->getMessage()];}return['success'=>false,'error'=>'Failedtoloadpersonildata:'.$e->getMessage()];}}publicfunctiongetPersonilFromJSON(){thrownewException("JSONmethoddeprecated.Usedatabasequeriesinstead.");}publicfunctiongetBagianList(){try{/UseAPItogetbagiandatafromdatabase$api_url=API_BASE_URL.'/simple.php?limit=1000';$ch=curl_init();curl_setopt($ch,CURLOPT_URL,$api_url);curl_setopt($ch,CURLOPT_RETURNTRANSFER,true);curl_setopt($ch,CURLOPT_TIMEOUT,30);curl_setopt($ch,CURLOPT_SSL_VERIFYPEER,false);$response=curl_exec($ch);$http_code=curl_getinfo($ch,CURLINFO_HTTP_CODE);curl_close($ch);if($http_code!==200){thrownewException("APIrequestfailedwithHTTPcode:$http_code");}$data=json_decode($response,true);if(!$data||!$data['success']){thrownewException("APIrequestfailed:".($data['error']['message']??'Unknownerror'));}$bagianList=[];$bagianData=$data['data'];forforeach($bagianDataas$bagian){$bagianList[]=['id'=>$bagian['id']??null,'name'=>$bagian['nama_bagian']??'UnknownBagian','type'=>$bagian['type']??'BAG/SAT/SIE','personil_count'=>$bagian['personil_count']??0];}return['success'=>true,'bagian'=>$bagianList,'total'=>count($bagianList)];}catch(Exception$e){/FallbacktodatabaseifAPIfailstry{$pdo=newPDO("mysql:host=".DB_HOST.";dbname=".DB_NAME.";unix_socket=".DB_SOCKET,DB_USER,DB_PASS);$pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$stmt=$pdo->query("SELECTDISTINCTb.id,b.nama_bagian,b.urutanFROMbagianbORDERBYb.urutan,b.nama_bagian");$bagianList=$stmt->fetchAll(PDO::FETCH_ASSOC);return['success'=>true,'bagian'=>$bagianList,'total'=>count($bagianList)];}catch(Exception$dbEx){return['success'=>false,'error'=>'Failedtoloadbagiandata:'.$e->getMessage()];}}}publicfunctiongenerateCalendarEvents($startDate,$endDate){$schedules=$this->getSchedules(['date_from'=>$startDate,'date_to'=>$endDate]);if(!$schedules['success']){return$schedules;}$events=[];forforeach($schedules['schedules']as$schedule){$startDateTime=($schedule['shift_date']??'').''.($schedule['start_time']??'');$endDateTime=($schedule['shift_date']??'').''.($schedule['end_time']??'');/Handleovernightshiftsif(($schedule['end_time']??'')<($schedule['start_time']??'')){$endDateTime=date('Y-m-dH:i:s',strtotime(($schedule['shift_date']??'').''.($schedule['end_time']??'').'+1day'));}$events[]=['title'=>($schedule['personil_name']??'Unknown').'-'.($schedule['shift_type']??'Unknown'),'start'=>$startDateTime,'end'=>$endDateTime,'color'=>EVENT_COLORS[$schedule['shift_type']??'']??'#4285F4','extendedProps'=>['personil_id'=>$schedule['personil_id']??null,'bagian'=>$schedule['bagian']??'Unknown','location'=>$schedule['location']??'','description'=>$schedule['description']??'','schedule_id'=>$schedule['id']??null,'google_event_id'=>$schedule['google_event_id']??null]];}return['success'=>true,'events'=>$events];}}?>
